static void dfs(char** g, int m, int n, int i, int j) {
    if (i<0||i>=m||j<0||j>=n||g[i][j]!='1') return;
    g[i][j]='0';
    dfs(g,m,n,i+1,j); dfs(g,m,n,i-1,j); dfs(g,m,n,i,j+1); dfs(g,m,n,i,j-1);
}
int numIslands(char** grid, int m, int* cs) {
    if (!m) return 0; int n=cs[0], cnt=0;
    for (int i=0;i<m;i++) for (int j=0;j<n;j++)
        if (grid[i][j]=='1') { cnt++; dfs(grid,m,n,i,j); }
    return cnt;
}
